    // Con 1 token (la COMA separadora) basta para considerar recuperado el parser
    // y permitir reportar el siguiente error en la misma lista de estilos.
    public int error_sync_size() { return 1; }

    private List<ErrorInfo> erroresSintacticos = new ArrayList<>();

    public List<ErrorInfo> getErroresSintacticos() {
        return erroresSintacticos;
    }

    public void syntax_error(Symbol s) {
        // Construir lista de tokens esperados traducidos al español
        List<Integer> ids = expected_token_ids();

        // Caso especial: draw() sin parámetros.
        if (esDrawSinParametrosVacio(s, ids)) {
            return;
        }

        List<String> esperados = new ArrayList<>();
        for (Integer id : ids) {
            String traducido = traductor(symbl_name_from_id(id));
            if (!traducido.equals("error")) esperados.add(traducido);
        }

        String encontrado = (s != null && s.value != null)
            ? s.value.toString()
            : traductor(symbl_name_from_id(s != null ? s.sym : 0));

        int linea   = s != null ? s.left  : 0;
        int columna = s != null ? s.right : 0;

        // Detectar si todos los esperados son atributos de bloque styles (llevan comillas dobles)
        boolean todosStyles = !esperados.isEmpty();
        if (todosStyles) {
            for (String esperado : esperados) {
                if (!(esperado.startsWith("\"") && esperado.endsWith("\""))) {
                    todosStyles = false;
                    break;
                }
            }
        }

        String mensaje;
        if (esperados.isEmpty()) {
            mensaje = "Token inesperado '" + encontrado + "'";
        } else if (todosStyles) {
            mensaje = "Se esperaba un atributo de styles entre comillas: "
                + String.join(", ", esperados)
                + ". Recuerda que los atributos dentro de styles [ ] deben escribirse entre comillas."
                + " Pero se encontró: '" + encontrado + "'";
        } else {
            mensaje = "Se esperaba: " + String.join(", ", esperados)
                + ". Pero se encontró: '" + encontrado + "'";
        }

        erroresSintacticos.add(new ErrorInfo(TipoError.SINTACTICO, mensaje, linea, columna));
    }

    private boolean esDrawSinParametrosVacio(Symbol s, List<Integer> ids) {
        if (s == null || s.sym != sym.PAREN_DER) return false;
        if (ids == null || ids.isEmpty()) return false;

        // Esperados típicos al inicio de una expresión
        List<Integer> inicioExpr = List.of(
            sym.VERTICAL, sym.HORIZONTAL, sym.MONO,
            sym.COLOR_NAME, sym.COLOR_HEX,
            sym.FUNC_POKEMON,
            sym.PAREN_IZQ, sym.COMODIN,
            sym.MENOS, sym.NOT,
            sym.IDENTIFICADOR, sym.NUMBER_LITERAL, sym.INICIO_CADENA
        );
        for (Integer id : ids) {
            if (!inicioExpr.contains(id)) return false;
        }

        // Verificar contexto sintáctico: ... DRAW PAREN_IZQ )
        if (stack == null || stack.size() < 2) return false;
        Symbol top = (Symbol) stack.peek();
        Symbol prev = (Symbol) stack.get(stack.size() - 2);
        return top.sym == sym.PAREN_IZQ && prev.sym == sym.DRAW;
    }

    public void report_error(String message, Object info) {
        // Los errores ya se gestionan en syntax_error; evitar mensajes duplicados
    }

    /** Traduce el nombre interno del token a una descripción legible en español. */
    private String traductor(String token) {
        if (token == null) return "desconocido";
        switch (token) {
            // --- Componentes UI ---
            case "SECTION":           return "SECTION";
            case "TABLE":             return "TABLE";
            case "TEXT":              return "TEXT";
            case "OPEN_QUESTION":     return "OPEN_QUESTION";
            case "DROP_QUESTION":     return "DROP_QUESTION";
            case "SELECT_QUESTION":   return "SELECT_QUESTION";
            case "MULTIPLE_QUESTION": return "MULTIPLE_QUESTION";
            // --- Atributos ---
            case "WIDTH":             return "width";
            case "HEIGHT":            return "height";
            case "POINT_X":           return "pointX";
            case "POINT_Y":           return "pointY";
            case "ORIENTATION":       return "orientation";
            case "ELEMENTS":          return "elements";
            case "STYLES":            return "styles";
            case "COLOR_ATTR":        return "\"color\"";
            case "BACKGROUND_COLOR":  return "\"background color\"";
            case "FONT_FAMILY":       return "\"font family\"";
            case "TEXT_SIZE":         return "\"text size\"";
            case "BORDER":            return "\"border\"";
            case "CONTENT":           return "content";
            case "LABEL":             return "label";
            case "OPTIONS":           return "options";
            case "CORRECT":           return "correct";
            // --- Tipos ---
            case "TYPE_NUMBER":       return "number";
            case "TYPE_STRING":       return "string";
            case "TYPE_SPECIAL":      return "special";
            // --- Orientación ---
            case "VERTICAL":          return "VERTICAL";
            case "HORIZONTAL":        return "HORIZONTAL";
            case "MONO":              return "MONO";
            case "SANS_SERIF":        return "SANS_SERIF";
            case "CURSIVE":           return "CURSIVE";
            case "LINE":              return "LINE";
            case "DOTTED":            return "DOTTED";
            case "DOUBLE":            return "DOUBLE";
            // --- POKEAPI ---
            case "NUMBER":            return "NUMBER";
            // --- Control ---
            case "IF":                return "IF";
            case "ELSE":              return "ELSE";
            case "WHILE":             return "WHILE";
            case "DO":                return "DO";
            case "FOR":               return "FOR";
            case "IN":                return "in";
            // --- Funciones especiales ---
            case "FUNC_POKEMON":      return "who_is_that_pokemon";
            case "DRAW":              return "draw";
            // --- Símbolos estructurales ---
            case "CORCHETE_IZQ":      return "'['";
            case "CORCHETE_DER":      return "']'";
            case "LLAVE_IZQ":         return "'{'";
            case "LLAVE_DER":         return "'}'";
            case "PAREN_IZQ":         return "'('";
            case "PAREN_DER":         return "')'";
            case "COMA":              return "','";
            case "DOS_PUNTOS":        return "':'";
            case "PUNTO_COMA":        return "';'";
            case "ASIGNACION":        return "'='";
            case "PUNTO":             return "'.'";
            case "COMODIN":           return "'?'";
            // --- Operadores aritméticos ---
            case "MAS":               return "'+'";
            case "MENOS":             return "'-'";
            case "POR":               return "'*'";
            case "DIV":               return "'/'";
            case "POTENCIA":          return "'^'";
            case "MODULO":            return "'%'";
            // --- Operadores relacionales ---
            case "MAYOR":             return "'>'";
            case "MENOR":             return "'<'";
            case "MAYOR_IGUAL":       return "'>='";
            case "MENOR_IGUAL":       return "'<='";
            case "IGUALDAD":          return "'=='";
            case "DIFERENTE":         return "'!!'";
            // --- Operadores lógicos ---
            case "OR":                return "'||'";
            case "AND":               return "'&&'";
            case "NOT":               return "'~'";
            // --- Literales e identificadores ---
            case "IDENTIFICADOR":     return "identificador";
            case "NUMBER_LITERAL":    return "número";
            case "INICIO_CADENA":     return "'\"' (inicio de cadena)";
            case "FIN_CADENA":        return "'\"' (fin de cadena)";
            case "CONTENIDO_CADENA":  return "contenido de cadena";
            // --- Emojis ---
            case "EMOJI_SMILE":       return "emoji @[:)]";
            case "EMOJI_SAD":         return "emoji @[:(]";
            case "EMOJI_SERIOUS":     return "emoji @[:|]";
            case "EMOJI_HEART":       return "emoji @[<3]";
            // --- Colores ---
            case "COLOR_NAME":        return "color (RED, BLUE, GREEN...)";
            case "COLOR_HEX":         return "color hexadecimal (#RRGGBB)";
            case "COLOR_RGB":         return "color RGB (r,g,b)";
            case "COLOR_HSL":         return "color HSL <h,s,l>";
            // --- Fin de archivo ---
            case "EOF":               return "fin de archivo";
            default:                  return token;
        }
    }

    /** Convierte sintaxis textual de emojis a sus caracteres Unicode. */
    private String normalizarEmojis(String texto) {
        if (texto == null || texto.isEmpty()) return texto;

        String out = texto;
        // Formas simbólicas
        out = out.replaceAll("@\\[:\\)+\\]", "😄");
        out = out.replaceAll("@\\[:\\(+\\]", "😢");
        out = out.replaceAll("@\\[:\\|+\\]", "😐");
        out = out.replaceAll("@\\[<+3+\\]", "❤️");

        // Formas nombradas
        out = out.replaceAll("@\\[:smile:\\]", "😄");
        out = out.replaceAll("@\\[:sad:\\]", "😢");
        out = out.replaceAll("@\\[:serious:\\]", "😐");
        out = out.replaceAll("@\\[:heart:\\]", "❤️");

        return out;
    }


